/**
 * @param array<int, string> $issues
 */
function httpIntegrationPrintResult(string $label, array $issues, int &$failures): void
{
    echo '=== ' . $label . " ===\n";
    if ($issues === []) {
        echo "OK\n";
        return;
    }

    $failures++;
    foreach ($issues as $issue) {
        echo '- ' . $issue . "\n";
    }
}

function httpIntegrationStatusCode(array $response): int
{
    if (preg_match('/\s(\d{3})\s/', (string)($response['status'] ?? ''), $matches) === 1) {
        return (int)$matches[1];
    }

    return 0;
}

/**
 * @param array{status:string,headers:array<int,string>,body:string} $response
 */
function httpIntegrationHeaderContains(array $response, string $name, string $needle): bool
{
    $headerPrefix = strtolower($name) . ':';
    foreach ($response['headers'] as $headerLine) {
        $headerLine = (string)$headerLine;
        if (str_starts_with(strtolower($headerLine), $headerPrefix) && stripos($headerLine, $needle) !== false) {
            return true;
        }
    }

    return false;
}

/**
 * @param array{id:string,cookie:string,csrf:string} $adminSession
 * @param list<string> $issues
 */
function httpIntegrationRefreshAdminSessionCsrf(string $baseUrl, array &$adminSession, array &$issues, string $label): void
{
    $freshTokenPage = fetchUrl($baseUrl . BASE_URL . '/admin/settings.php', $adminSession['cookie'], 0);
    $freshCsrf = extractHiddenInputValue($freshTokenPage['body'], 'csrf_token');
    if (httpIntegrationStatusCode($freshTokenPage) !== 200 || $freshCsrf === '') {
        $issues[] = $label . ' neobnovil aktuální csrf_token pro další administrační scénáře';
        return;
    }

    $adminSession['csrf'] = $freshCsrf;
}

/**
 * @param array{id:string,cookie:string,csrf:string} $adminSession
 * @param list<string> $issues
 * @return array{status:string,headers:array<int,string>,body:string}
 */
function httpIntegrationFetchConfirmedJsonExport(string $baseUrl, array &$adminSession, array &$issues, string $label): array
{
    $exportPage = fetchUrl($baseUrl . BASE_URL . '/admin/export.php', $adminSession['cookie'], 0);
    $exportCsrf = extractHiddenInputValue($exportPage['body'], 'csrf_token');
    if (httpIntegrationStatusCode($exportPage) !== 200
        || $exportCsrf === ''
        || httpIntegrationHeaderContains($exportPage, 'Content-Disposition', 'attachment')
        || !str_contains($exportPage['body'], 'JSON export obsahuje články, stránky, média metadata')) {
        $issues[] = $label . ' nevykreslil review formulář JSON exportu';
    }

    $exportResponse = postUrl(
        $baseUrl . BASE_URL . '/admin/export.php',
        [
            'csrf_token' => $exportCsrf,
            'confirm_json_export' => '1',
        ],
        $adminSession['cookie'],
        0
    );
    if (httpIntegrationStatusCode($exportResponse) !== 200
        || !httpIntegrationHeaderContains($exportResponse, 'Content-Disposition', 'attachment')
        || !httpIntegrationHeaderContains($exportResponse, 'Content-Disposition', 'filename*=')
        || !httpIntegrationHeaderContains($exportResponse, 'Cache-Control', 'no-store')
        || !httpIntegrationHeaderContains($exportResponse, 'X-Content-Type-Options', 'nosniff')) {
        $issues[] = $label . ' nevrátil potvrzený JSON export s bezpečnými download hlavičkami';
    }

    httpIntegrationRefreshAdminSessionCsrf($baseUrl, $adminSession, $issues, $label);

    return $exportResponse;
}

/**
 * @param array{status:string,headers:array<int,string>,body:string} $response
 */
function httpIntegrationHeaderValue(array $response, string $name): string
{
    $headerPrefix = strtolower($name) . ':';
    foreach ($response['headers'] as $headerLine) {
        $headerLine = (string)$headerLine;
        if (str_starts_with(strtolower($headerLine), $headerPrefix)) {
            return trim(substr($headerLine, strlen($name) + 1));
        }
    }

    return '';
}

/**
 * @param array{status:string,headers:array<int,string>,body:string} $response
 * @param list<string> $allowedMethods
 */
function httpIntegrationMethodGuardOk(array $response, array $allowedMethods): bool
{
    $normalizedAllowedMethods = array_values(array_unique(array_map(
        static fn (string $method): string => strtoupper($method),
        $allowedMethods
    )));
    $knownMethods = ['GET', 'HEAD', 'POST', 'PUT', 'PATCH', 'DELETE'];
    if (
        httpIntegrationStatusCode($response) !== 405
        || !httpIntegrationHeaderContains($response, 'Cache-Control', 'no-store')
        || !httpIntegrationHeaderContains($response, 'Cache-Control', 'max-age=0')
        || !httpIntegrationHeaderContains($response, 'X-Robots-Tag', 'noindex')
        || !httpIntegrationHeaderContains($response, 'X-Robots-Tag', 'nofollow')
        || !httpIntegrationHeaderContains($response, 'X-Robots-Tag', 'noarchive')
        || !httpIntegrationHeaderContains($response, 'Referrer-Policy', 'no-referrer')
        || !httpIntegrationHeaderContains($response, 'X-Content-Type-Options', 'nosniff')
        || !httpIntegrationHeaderContains($response, 'Content-Type', 'text/plain; charset=UTF-8')
    ) {
        return false;
    }

    foreach ($normalizedAllowedMethods as $allowedMethod) {
        if (!httpIntegrationHeaderContains($response, 'Allow', $allowedMethod)) {
            return false;
        }
    }
    foreach ($knownMethods as $knownMethod) {
        if (!in_array($knownMethod, $normalizedAllowedMethods, true) && httpIntegrationHeaderContains($response, 'Allow', $knownMethod)) {
            return false;
        }
    }

    return true;
}

/**
 * @param array{status:string,headers:array<int,string>,body:string} $response
 */
function httpIntegrationReadOnlyMethodGuardOk(array $response): bool
{
    return httpIntegrationMethodGuardOk($response, ['GET', 'HEAD']);
}

/**
 * @param array{status:string,headers:array<int,string>,body:string} $response
 * @param list<string> $allowedMethods
 */
function httpIntegrationJsonMethodGuardOk(array $response, array $allowedMethods): bool
{
    $normalizedAllowedMethods = array_values(array_unique(array_map(
        static fn (string $method): string => strtoupper($method),
        $allowedMethods
    )));
    $knownMethods = ['GET', 'HEAD', 'POST', 'PUT', 'PATCH', 'DELETE'];
    if (
        httpIntegrationStatusCode($response) !== 405
        || !httpIntegrationHeaderContains($response, 'Cache-Control', 'no-store')
        || !httpIntegrationHeaderContains($response, 'Cache-Control', 'max-age=0')
        || !httpIntegrationHeaderContains($response, 'X-Robots-Tag', 'noindex')
        || !httpIntegrationHeaderContains($response, 'X-Robots-Tag', 'nofollow')
        || !httpIntegrationHeaderContains($response, 'X-Robots-Tag', 'noarchive')
        || !httpIntegrationHeaderContains($response, 'Referrer-Policy', 'no-referrer')
        || !httpIntegrationHeaderContains($response, 'X-Content-Type-Options', 'nosniff')
        || !httpIntegrationHeaderContains($response, 'Content-Type', 'application/json; charset=UTF-8')
    ) {
        return false;
    }

    foreach ($normalizedAllowedMethods as $allowedMethod) {
        if (!httpIntegrationHeaderContains($response, 'Allow', $allowedMethod)) {
            return false;
        }
    }
    foreach ($knownMethods as $knownMethod) {
        if (!in_array($knownMethod, $normalizedAllowedMethods, true) && httpIntegrationHeaderContains($response, 'Allow', $knownMethod)) {
            return false;
        }
    }

    $decodedPayload = json_decode($response['body'], true);
    return is_array($decodedPayload) && trim((string)($decodedPayload['request_id'] ?? '')) !== '';
}

function httpIntegrationSettingValue(PDO $pdo, string $key): string
{
    $stmt = $pdo->prepare("SELECT value FROM cms_settings WHERE `key` = ?");
    $stmt->execute([$key]);
    $value = $stmt->fetchColumn();
    return is_string($value) ? $value : '';
}

/**
 * @param array<string, string> $settings
 */
function httpIntegrationRestoreSettings(array $settings): void
{
