        if (httpIntegrationStatusCode($disabledModuleResponse) !== 302) {
            $publicModuleNavigationIssues[] = 'vypnutý veřejný modul ' . $moduleKey . ' (' . $publicModulePath . ') nevrátil redirect';
            continue;
