            $publicModuleNavigationIssues[] = 'vypnutý veřejný modul ' . $moduleKey . ' nepřesměroval na homepage';
        }
    }

    foreach (array_keys(moduleNavigationDefaults()) as $moduleKey) {
        saveSetting(moduleSettingKey($moduleKey), '1');
