                'id="poll-options-error"',
                'Nechte nejvýše deset možností odpovědi a přebytečné řádky odeberte.',
            ],
            'forbidden' => ['Maximální počet možností je 10.'],
        ],
    ] as $pollValidationError => $pollValidationSpec) {
