        $pollCsvReviewResponse = fetchUrl($pollCsvUrl, $adminSession['cookie'], 0);
        $pollCsvCsrf = extractHiddenInputValue($pollCsvReviewResponse['body'], 'csrf_token');
        if (httpIntegrationStatusCode($pollCsvReviewResponse) !== 200
