            email, password, first_name, last_name, nickname, phone, role, is_superadmin, is_confirmed, created_at
         ) VALUES (?, ?, 'HTTP', 'Prefill Kontakt', 'HTTP Prefill', ?, 'public', 0, 1, NOW())"
    )->execute([
        $prefillPublicEmail,
        password_hash('HttpPublicPrefill123!', PASSWORD_DEFAULT),
        $prefillPublicPhone,
    ]);
