                'end_time' => '10:00',
                'party_size' => '1',
                'notes' => '',
            ],
            'expected' => [
                'role="alert" class="error" id="form-error" aria-atomic="true">Rezervaci nejde vytvořit bez zdroje.',
                'aria-invalid="true" aria-describedby="resource_id-error"',
                'id="resource_id-error"',
