        ],
        'user_required' => [
            'post' => [
                'mode' => 'user',
                'resource_id' => (string)$resourceId,
                'user_id' => '',
                'booking_date' => $bookingDate,
                'start_time' => '09:00',
                'end_time' => '10:00',
                'party_size' => '1',
                'notes' => '',
