            'expected' => [
                'role="alert" class="error" id="form-error" aria-atomic="true">Rezervaci pro registrovaného zákazníka nejde vytvořit bez uživatele.',
                'aria-invalid="true" aria-describedby="user_id-error"',
                'id="user_id-error"',
