    $blogSlugRedirectSnapshotStmt->execute([$blogSlugRedirectMainId]);
    $blogSlugRedirectSnapshot = $blogSlugRedirectSnapshotStmt->fetchAll(PDO::FETCH_COLUMN) ?: [];

    try {
