        $pdo->prepare("UPDATE cms_blogs SET slug = ? WHERE id = ?")->execute([$blogSlugRedirectTemporarySlug, $blogSlugRedirectMainId]);
        clearBlogCache();

        $blogSlugChecks = [
            [
