    $emptyMediaUploadPage = fetchUrl($mediaAdminUrl, $adminSession['cookie'], 0);
    foreach ([
        'Vyberte alespoň jeden podporovaný soubor do ' . $defaultMediaUploadLimitLabel,
        'aria-invalid="true"',
        'aria-describedby="media-upload-help media-upload-error"',
