        }
        if (httpIntegrationStatusCode($mediaDeleteMissingConfirmResponse) !== 302
            || !responseHasLocationHeader($mediaDeleteMissingConfirmResponse['headers'], $deleteUnusedListPath, $baseUrl)
            || !str_contains($mediaDeleteMissingConfirmPage['body'], '<p class="error" role="alert" aria-atomic="true">Před smazáním zaškrtněte potvrzení kontroly konkrétního souboru.')
            || !str_contains($mediaDeleteMissingConfirmPage['body'], 'id="' . $deleteUnusedFieldErrorId . '"')
            || !httpIntegrationInputHasAttributes($mediaDeleteMissingConfirmPage['body'], $deleteUnusedConfirmId, [
                'aria-invalid' => 'true',
                'aria-describedby' => $deleteUnusedReviewId . ' ' . $deleteUnusedFieldErrorId,
            ])
            || !$mediaDeleteStillExists
            || ($deleteUnusedMediaPath !== '' && !is_file($deleteUnusedMediaPath))
            || $mediaDeleteLogCountAfterMissingConfirm !== $mediaDeleteLogCountBefore) {
            $mediaIssues[] = 'individuální delete média bez potvrzení nezobrazil field-level chybu nebo změnil DB/soubor/audit log';
        }

        $mediaDeleteConfirmedCsrf = extractHiddenInputValue($mediaDeleteMissingConfirmPage['body'], 'csrf_token');
        $mediaDeleteConfirmedResponse = postUrl(
            $mediaAdminUrl,
            [
                'csrf_token' => $mediaDeleteConfirmedCsrf,
                'action' => 'delete',
                'media_id' => (string)$deleteUnusedMediaId,
                $deleteUnusedConfirmField => '1',
                'return_to' => $deleteUnusedListPath,
            ],
            $adminSession['cookie'],
            0
        );
        $mediaDeleteSuccessPage = fetchUrl($baseUrl . $deleteUnusedListPath, $adminSession['cookie'], 0);
        $mediaDeleteLogCountAfterConfirmed = (int)$pdo->query("SELECT COUNT(*) FROM cms_log WHERE action = 'media_delete'")->fetchColumn();
        $mediaDeleteConfirmedFileOk = true;
        if ($deleteUnusedMediaPath !== '') {
            $mediaDeleteConfirmedFileOk = false;
            for ($mediaDeleteFileAttempt = 0; $mediaDeleteFileAttempt < 20; $mediaDeleteFileAttempt++) {
                clearstatcache(true, $deleteUnusedMediaPath);
                if (!is_file($deleteUnusedMediaPath)) {
                    $mediaDeleteConfirmedFileOk = true;
                    break;
                }
                usleep(50000);
            }
        }
        $mediaDeleteConfirmedStatusOk = httpIntegrationStatusCode($mediaDeleteConfirmedResponse) === 302;
        $mediaDeleteConfirmedLocationOk = responseHasLocationHeader($mediaDeleteConfirmedResponse['headers'], $deleteUnusedListPath, $baseUrl);
        $mediaDeleteConfirmedFlashOk = str_contains($mediaDeleteSuccessPage['body'], '<p class="success" role="status">Soubor byl smazán.</p>');
        $mediaDeleteConfirmedDbOk = httpIntegrationFetchMediaById($pdo, $deleteUnusedMediaId) === null;
        $mediaDeleteConfirmedLogOk = $mediaDeleteLogCountAfterConfirmed === $mediaDeleteLogCountBefore + 1;
        if (!$mediaDeleteConfirmedStatusOk
            || !$mediaDeleteConfirmedLocationOk
            || !$mediaDeleteConfirmedFlashOk
            || !$mediaDeleteConfirmedDbOk
            || !$mediaDeleteConfirmedFileOk
            || !$mediaDeleteConfirmedLogOk) {
            $mediaIssues[] = 'potvrzený individuální delete média nevrátil PRG stav, nesmazal DB/soubor nebo nezapsal audit log'
                . ' (status=' . ($mediaDeleteConfirmedStatusOk ? 'ok' : (string)httpIntegrationStatusCode($mediaDeleteConfirmedResponse))
                . ', location=' . ($mediaDeleteConfirmedLocationOk ? 'ok' : 'fail')
                . ', flash=' . ($mediaDeleteConfirmedFlashOk ? 'ok' : 'fail')
                . ', db=' . ($mediaDeleteConfirmedDbOk ? 'ok' : 'fail')
                . ', file=' . ($mediaDeleteConfirmedFileOk ? 'ok' : 'fail')
                . ', log=' . ($mediaDeleteConfirmedLogOk ? 'ok' : ($mediaDeleteLogCountAfterConfirmed . '/' . ($mediaDeleteLogCountBefore + 1))) . ')';
        }

        $bulkPrivateResponse = postUrl(
            $mediaAdminUrl,
            [
                'csrf_token' => $adminSession['csrf'],
                'action' => 'bulk',
                'bulk_action' => 'make_private',
                'media_ids' => [(string)$usedMedia['id'], (string)$bulkUnusedMedia['id']],
                'return_to' => $mediaReturnPath,
            ],
            $adminSession['cookie'],
            0
        );
        if (httpIntegrationStatusCode($bulkPrivateResponse) !== 302) {
            $mediaIssues[] = 'bulk make_private nevrátil 302 redirect';
        }
        $bulkPrivatePage = fetchUrl($mediaAdminUrl, $adminSession['cookie'], 0);
        if (!str_contains($bulkPrivatePage['body'], 'Soukromě označeno 1 médií.')) {
            $mediaIssues[] = 'bulk make_private nezobrazil success flash zprávu';
        }
        if (!str_contains($bulkPrivatePage['body'], 'U 1 médií byla akce zablokována kvůli použití nebo chybě přesunu.')) {
            $mediaIssues[] = 'bulk make_private nezobrazil blokaci použitého média';
        }
        $usedMediaAfterBulkPrivate = httpIntegrationFetchMediaById($pdo, (int)$usedMedia['id']);
        $bulkUnusedMediaAfterPrivate = httpIntegrationFetchMediaById($pdo, (int)$bulkUnusedMedia['id']);
        if ($usedMediaAfterBulkPrivate === null || normalizeMediaVisibility((string)($usedMediaAfterBulkPrivate['visibility'] ?? 'public')) !== 'public') {
            $mediaIssues[] = 'bulk make_private změnil visibility použitého média';
        }
        if ($bulkUnusedMediaAfterPrivate === null || normalizeMediaVisibility((string)($bulkUnusedMediaAfterPrivate['visibility'] ?? 'public')) !== 'private') {
            $mediaIssues[] = 'bulk make_private nepřepnul nepoužité médium do soukromého režimu';
        } elseif (!str_starts_with(mediaFileUrl($bulkUnusedMediaAfterPrivate), BASE_URL . '/media/file.php?id=' . (int)$bulkUnusedMedia['id'])) {
            $mediaIssues[] = 'bulk make_private nepřepnul canonical URL nepoužitého média na chráněný endpoint';
        }

        if ($mediaCollectionId > 0) {
            $bulkCollectionDefaultsResponse = postUrl(
                $mediaAdminUrl,
                [
                    'csrf_token' => $adminSession['csrf'],
                    'action' => 'bulk',
                    'bulk_action' => 'apply_collection_defaults',
                    'bulk_collection_id' => (string)$mediaCollectionId,
                    'media_ids' => [(string)$bulkUnusedMedia['id']],
                    'return_to' => $mediaReturnPath,
                ],
                $adminSession['cookie'],
                0
            );
            if (httpIntegrationStatusCode($bulkCollectionDefaultsResponse) !== 302) {
                $mediaIssues[] = 'bulk apply_collection_defaults nevrátil 302 redirect';
            }
            $bulkCollectionDefaultsPage = fetchUrl($mediaAdminUrl, $adminSession['cookie'], 0);
            if (!str_contains($bulkCollectionDefaultsPage['body'], 'Výchozí metadata z kolekce doplněna u 1 médií.')) {
                $mediaIssues[] = 'bulk apply_collection_defaults nezobrazil success flash zprávu';
            }
            $bulkUnusedAfterDefaults = httpIntegrationFetchMediaById($pdo, (int)$bulkUnusedMedia['id']);
            if ($bulkUnusedAfterDefaults === null
                || (int)($bulkUnusedAfterDefaults['collection_id'] ?? 0) !== $mediaCollectionId
                || (string)($bulkUnusedAfterDefaults['credit'] ?? '') !== 'HTTP výchozí kredit'
                || (string)($bulkUnusedAfterDefaults['license_label'] ?? '') !== 'HTTP licence') {
                $mediaIssues[] = 'bulk apply_collection_defaults nepřiřadil kolekci nebo nedoplnil výchozí metadata';
            }
        }

        $bulkDeleteResponse = postUrl(
            $mediaAdminUrl,
            [
                'csrf_token' => $adminSession['csrf'],
                'action' => 'bulk',
                'bulk_action' => 'delete_unused',
                'media_ids' => [(string)$usedMedia['id'], (string)$bulkUnusedMedia['id']],
                'return_to' => $mediaReturnPath,
            ],
            $adminSession['cookie'],
            0
        );
        if (httpIntegrationStatusCode($bulkDeleteResponse) !== 302) {
            $mediaIssues[] = 'bulk delete_unused nevrátil 302 redirect';
        }
        $bulkDeletePage = fetchUrl($mediaAdminUrl, $adminSession['cookie'], 0);
        if (!str_contains($bulkDeletePage['body'], 'Smazáno 1 nepoužitých médií.')) {
            $mediaIssues[] = 'bulk delete_unused nezobrazil success flash zprávu';
        }
        if (!str_contains($bulkDeletePage['body'], 'U 1 médií byla akce zablokována kvůli použití nebo chybě přesunu.')) {
            $mediaIssues[] = 'bulk delete_unused nezobrazil blokaci použitého média';
        }
        if (httpIntegrationFetchMediaById($pdo, (int)$bulkUnusedMedia['id']) !== null) {
            $mediaIssues[] = 'bulk delete_unused nesmazal nepoužité médium';
        }
        if (httpIntegrationFetchMediaById($pdo, (int)$usedMedia['id']) === null) {
            $mediaIssues[] = 'bulk delete_unused smazal použité médium';
        }
    }

    httpIntegrationPrintResult('media_admin_http', $mediaIssues, $failures);

    $publicFormIssues = [];
    $publicFormSlug = uniqueFormSlug($pdo, 'http-integration-form-' . bin2hex(random_bytes(4)));
