    if (!httpIntegrationInputHasAttributes($publicFormInitialBody, 'field-full_name', ['autocomplete' => 'name'])
        || !httpIntegrationInputHasAttributes($publicFormInitialBody, 'field-contact_email', ['autocomplete' => 'email'])
        || !httpIntegrationInputHasAttributes($publicFormInitialBody, 'field-project_url', ['autocomplete' => 'url'])
        || !httpIntegrationInputHasAttributes($publicFormInitialBody, 'field-street_address', ['autocomplete' => 'street-address'])
        || !httpIntegrationInputHasAttributes($publicFormInitialBody, 'field-postal_code', ['autocomplete' => 'postal-code'])
        || !httpIntegrationInputHasAttributes($publicFormInitialBody, 'field-city', ['autocomplete' => 'address-level2'])
        || !httpIntegrationInputHasAttributes($publicFormInitialBody, 'field-region', ['autocomplete' => 'address-level1'])
        || !httpIntegrationInputHasAttributes($publicFormInitialBody, 'field-country', ['autocomplete' => 'country-name'])
        || !httpIntegrationInputHasAttributes($publicFormInitialBody, 'field-job_title', ['autocomplete' => 'organization-title'])
